'with w_player as (
    select id player_id
    from wmg_players
   where discord_id = to_number(:discord_id default null on conversion error)
)
select pos
     , discord_id
     , player_name
     , score
     , isApproved
from (
select l.pos
     , to_char(l.discord_id) discord_id
     , l.player_name
     , l.score
     , case when l.approved_flag = ''Y'' then ''true'' else ''false'' end isApproved
     , row_number() over (order by l.pos, nvl(l.approved_on, l.created_on)) rn
     , count(*) over () n
     , l.approved_on
from wmg_leaderboards_all_v l
where l.course_code = :code
  and (l.approved_flag = ''Y'' 
   or (l.approved_flag is null and l.player_id = (select p.player_id from w_player p))
  )
  and (l.pos <= 20 or l.player_id = (select p.player_id from w_player p))
)
where (pos <= case when n > 25 then 10 else 20 end or isApproved = ''false'')
order by pos, approved_on
');

