'with w_player as (
  select id player_id
  from wmg_players
  where discord_id = to_number(:discord_id default null on conversion error)
)
, w_leaderboard as (
  select l.pos
       , to_char(l.discord_id) discord_id
       , l.player_name
       , l.round_speed
       , l.round_speed_prepared
       , l.approved_flag
       , l.approved_on
       , nvl(l.round_speed - lag(l.round_speed) over (order by l.pos), interval ''0'' second) as time_behind
  from wmg_race_leaderboards_all_v l
  where l.course_code = :code
  and (l.approved_flag = ''Y'' or (l.approved_flag is null and l.player_id = (select p.player_id from w_player p)))
  and (l.pos <= 20 or l.player_id = (select p.player_id from w_player p))
)
select l.pos
     , l.discord_id
     , l.player_name
     , l.round_speed
     , l.round_speed_prepared
     , l.time_behind
     , extract(day from l.time_behind) * 86400 + 
       extract(hour from l.time_behind) * 3600 + 
       extract(minute from l.time_behind' || ') * 60 + 
       extract(second from l.time_behind) as time_behind_prepared
     , case when l.approved_flag = ''Y'' then ''true'' else ''false'' end isApproved
from w_leaderboard l
order by l.pos, l.approved_on
');

